"""Clustering algorithms: KMeans, DBSCAN, AgglomerativeClustering,
MiniBatchKMeans, SpectralClustering, MeanShift, OPTICS, Birch,
AffinityPropagation, BisectingKMeans, HDBSCAN, FeatureAgglomeration."""
import numpy as np
from sklearn.base import BaseEstimator, TransformerMixin


class KMeans(BaseEstimator):
    def __init__(self, n_clusters=8, *, init='k-means++', n_init='auto',
                 max_iter=300, tol=1e-4, verbose=0, random_state=None,
                 copy_x=True, algorithm='lloyd'):
        self.n_clusters = n_clusters
        self.init = init
        self.n_init = n_init if n_init != 'auto' else 10
        self.max_iter = max_iter
        self.tol = tol
        self.verbose = verbose
        self.random_state = random_state
        self.copy_x = copy_x
        self.algorithm = algorithm
        self.cluster_centers_ = None
        self.labels_ = None
        self.inertia_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        best_inertia = np.inf
        for _ in range(self.n_init):
            idx = rng.choice(X.shape[0], self.n_clusters, replace=False)
            centers = X[idx].copy()
            for _ in range(self.max_iter):
                dists = np.sqrt(((X[:, None] - centers[None]) ** 2).sum(axis=2))
                labels = np.argmin(dists, axis=1)
                new_centers = np.array([X[labels == k].mean(axis=0) if np.any(labels == k) else centers[k]
                                        for k in range(self.n_clusters)])
                if np.max(np.abs(new_centers - centers)) < self.tol:
                    centers = new_centers
                    break
                centers = new_centers
            inertia = sum(np.sum((X[labels == k] - centers[k]) ** 2) for k in range(self.n_clusters))
            if inertia < best_inertia:
                best_inertia = inertia
                self.cluster_centers_ = centers
                self.labels_ = labels
                self.inertia_ = inertia
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
        return np.argmin(dists, axis=1)

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


class DBSCAN(BaseEstimator):
    def __init__(self, eps=0.5, *, min_samples=5, metric='euclidean',
                 metric_params=None, algorithm='auto', leaf_size=30, p=None,
                 n_jobs=None):
        self.eps = eps
        self.min_samples = min_samples
        self.metric = metric
        self.metric_params = metric_params
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.p = p
        self.n_jobs = n_jobs
        self.labels_ = None
        self.core_sample_indices_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = len(X)
        # Compute pairwise distances
        dists = np.sqrt(((X[:, None] - X[None]) ** 2).sum(axis=2))
        # Find neighbors within eps for each point
        neighborhoods = [np.where(dists[i] <= self.eps)[0] for i in range(n)]
        # Identify core points
        core_mask = np.array([len(nb) >= self.min_samples for nb in neighborhoods])
        self.core_sample_indices_ = np.where(core_mask)[0]
        labels = np.full(n, -1, dtype=int)
        cluster_id = 0
        for i in range(n):
            if not core_mask[i] or labels[i] != -1:
                continue
            # BFS to expand cluster
            queue = [i]
            labels[i] = cluster_id
            head = 0
            while head < len(queue):
                point = queue[head]
                head += 1
                if core_mask[point]:
                    for nb in neighborhoods[point]:
                        if labels[nb] == -1:
                            labels[nb] = cluster_id
                            queue.append(nb)
            cluster_id += 1
        self.labels_ = labels
        return self

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


class AgglomerativeClustering(BaseEstimator):
    def __init__(self, n_clusters=2, *, metric='euclidean', memory=None,
                 connectivity=None, compute_full_tree='auto',
                 linkage='single', distance_threshold=None,
                 compute_distances=False):
        self.n_clusters = n_clusters
        self.metric = metric
        self.memory = memory
        self.connectivity = connectivity
        self.compute_full_tree = compute_full_tree
        self.linkage = linkage
        self.distance_threshold = distance_threshold
        self.compute_distances = compute_distances
        self.labels_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = len(X)
        # Pairwise distance matrix
        dists = np.sqrt(((X[:, None] - X[None]) ** 2).sum(axis=2))
        # Each point starts as its own cluster
        clusters = {i: [i] for i in range(n)}
        # Set diagonal to inf
        np.fill_diagonal(dists, np.inf)
        # Merge until n_clusters remain
        active = set(range(n))
        while len(active) > self.n_clusters:
            # Find closest pair among active clusters
            min_dist = np.inf
            merge_a, merge_b = -1, -1
            active_list = sorted(active)
            for idx_i in range(len(active_list)):
                for idx_j in range(idx_i + 1, len(active_list)):
                    ci, cj = active_list[idx_i], active_list[idx_j]
                    d = dists[ci, cj]
                    if d < min_dist:
                        min_dist = d
                        merge_a, merge_b = ci, cj
            # Merge b into a
            clusters[merge_a].extend(clusters[merge_b])
            del clusters[merge_b]
            active.remove(merge_b)
            # Update distances
            for other in active:
                if other == merge_a:
                    continue
                if self.linkage == 'single':
                    new_dist = min(dists[merge_a, other], dists[merge_b, other])
                elif self.linkage == 'complete':
                    new_dist = max(dists[merge_a, other], dists[merge_b, other])
                else:  # average
                    na = len(clusters[merge_a]) - len(clusters.get(merge_b, []))
                    nb = len(clusters.get(merge_b, [0]))
                    # Weighted average of old distances
                    new_dist = (dists[merge_a, other] + dists[merge_b, other]) / 2
                dists[merge_a, other] = new_dist
                dists[other, merge_a] = new_dist
        # Assign labels
        self.labels_ = np.zeros(n, dtype=int)
        for label, (_, members) in enumerate(sorted(clusters.items())):
            for m in members:
                self.labels_[m] = label
        return self

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# MiniBatchKMeans
# ---------------------------------------------------------------------------

class MiniBatchKMeans(BaseEstimator):
    """Mini-batch K-Means clustering."""

    def __init__(self, n_clusters=8, *, init='k-means++', max_iter=100,
                 batch_size=1024, verbose=0, compute_labels=True,
                 random_state=None, tol=0.0, max_no_improvement=10,
                 init_size=None, n_init=3, reassignment_ratio=0.01):
        self.n_clusters = n_clusters
        self.init = init
        self.max_iter = max_iter
        self.batch_size = batch_size
        self.verbose = verbose
        self.compute_labels = compute_labels
        self.random_state = random_state
        self.tol = tol
        self.max_no_improvement = max_no_improvement
        self.init_size = init_size
        self.n_init = n_init
        self.reassignment_ratio = reassignment_ratio
        self.cluster_centers_ = None
        self.labels_ = None
        self.inertia_ = None

    def _init_centroids(self, X, rng):
        if self.init == 'k-means++':
            centers = [X[rng.randint(X.shape[0])]]
            for _ in range(1, self.n_clusters):
                dists = np.min(np.array([np.sum((X - c) ** 2, axis=1) for c in centers]), axis=0)
                probs = dists / dists.sum()
                idx = rng.choice(X.shape[0], p=probs)
                centers.append(X[idx])
            return np.array(centers)
        idx = rng.choice(X.shape[0], self.n_clusters, replace=False)
        return X[idx].copy()

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        rng = np.random.RandomState(self.random_state)
        best_inertia = np.inf
        for _ in range(self.n_init):
            centers = self._init_centroids(X, rng)
            counts = np.zeros(self.n_clusters)
            no_improvement = 0
            prev_inertia = np.inf
            for iteration in range(self.max_iter):
                idx = rng.choice(X.shape[0], min(self.batch_size, X.shape[0]), replace=False)
                batch = X[idx]
                dists = np.sqrt(((batch[:, None] - centers[None]) ** 2).sum(axis=2))
                batch_labels = np.argmin(dists, axis=1)
                for k in range(self.n_clusters):
                    mask = batch_labels == k
                    if not np.any(mask):
                        continue
                    count = mask.sum()
                    counts[k] += count
                    eta = count / counts[k]
                    centers[k] = (1 - eta) * centers[k] + eta * batch[mask].mean(axis=0)
                dists_full = np.sqrt(((X[:, None] - centers[None]) ** 2).sum(axis=2))
                labels = np.argmin(dists_full, axis=1)
                inertia = sum(np.sum((X[labels == k] - centers[k]) ** 2) for k in range(self.n_clusters))
                if prev_inertia - inertia < self.tol:
                    no_improvement += 1
                else:
                    no_improvement = 0
                prev_inertia = inertia
                if self.max_no_improvement and no_improvement >= self.max_no_improvement:
                    break
            if inertia < best_inertia:
                best_inertia = inertia
                self.cluster_centers_ = centers.copy()
                self.inertia_ = inertia
        if self.compute_labels:
            dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
            self.labels_ = np.argmin(dists, axis=1)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
        return np.argmin(dists, axis=1)

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# SpectralClustering
# ---------------------------------------------------------------------------

class SpectralClustering(BaseEstimator):
    """Spectral clustering via graph Laplacian eigenvectors."""

    def __init__(self, n_clusters=8, *, eigen_solver=None, n_components=None,
                 random_state=None, n_init=10, gamma=1.0, affinity='rbf',
                 n_neighbors=10, eigen_tol='auto', assign_labels='kmeans',
                 degree=3, coef0=1, kernel_params=None, n_jobs=None,
                 verbose=False):
        self.n_clusters = n_clusters
        self.eigen_solver = eigen_solver
        self.n_components = n_components if n_components else n_clusters
        self.random_state = random_state
        self.n_init = n_init
        self.gamma = gamma
        self.affinity = affinity
        self.n_neighbors = n_neighbors
        self.eigen_tol = eigen_tol
        self.assign_labels = assign_labels
        self.degree = degree
        self.coef0 = coef0
        self.kernel_params = kernel_params
        self.n_jobs = n_jobs
        self.verbose = verbose
        self.labels_ = None
        self.affinity_matrix_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = X.shape[0]
        # Build affinity matrix
        dists_sq = ((X[:, None] - X[None]) ** 2).sum(axis=2)
        if self.affinity == 'rbf':
            self.affinity_matrix_ = np.exp(-self.gamma * dists_sq)
        elif self.affinity == 'nearest_neighbors':
            A = np.zeros((n, n))
            for i in range(n):
                nn_idx = np.argsort(dists_sq[i])[:self.n_neighbors + 1]
                A[i, nn_idx] = 1
            self.affinity_matrix_ = np.maximum(A, A.T)
        else:
            self.affinity_matrix_ = np.exp(-self.gamma * dists_sq)
        # Normalized Laplacian
        D = np.diag(self.affinity_matrix_.sum(axis=1))
        D_inv_sqrt = np.diag(1.0 / np.sqrt(np.maximum(np.diag(D), 1e-10)))
        L_norm = np.eye(n) - D_inv_sqrt @ self.affinity_matrix_ @ D_inv_sqrt
        # Eigen-decomposition
        eigenvalues, eigenvectors = np.linalg.eigh(L_norm)
        # Take the smallest n_components eigenvectors
        nc = self.n_components
        embedding = eigenvectors[:, :nc]
        # Normalize rows
        norms = np.linalg.norm(embedding, axis=1, keepdims=True)
        norms[norms == 0] = 1.0
        embedding = embedding / norms
        # KMeans on embedding
        km = KMeans(n_clusters=self.n_clusters, n_init=self.n_init,
                    random_state=self.random_state)
        km.fit(embedding)
        self.labels_ = km.labels_
        return self

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# MeanShift
# ---------------------------------------------------------------------------

class MeanShift(BaseEstimator):
    """Mean-shift clustering via iterative mode seeking."""

    def __init__(self, *, bandwidth=None, seeds=None, bin_seeding=False,
                 min_bin_freq=1, cluster_all=True, n_jobs=None, max_iter=300):
        self.bandwidth = bandwidth
        self.seeds = seeds
        self.bin_seeding = bin_seeding
        self.min_bin_freq = min_bin_freq
        self.cluster_all = cluster_all
        self.n_jobs = n_jobs
        self.max_iter = max_iter
        self.cluster_centers_ = None
        self.labels_ = None

    @staticmethod
    def _estimate_bandwidth(X):
        """Estimate bandwidth using median of pairwise distances."""
        dists = np.sqrt(((X[:, None] - X[None]) ** 2).sum(axis=2))
        return np.median(dists) * 0.3

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        bw = self.bandwidth if self.bandwidth is not None else self._estimate_bandwidth(X)
        if self.seeds is not None:
            seeds = np.asarray(self.seeds, dtype=float)
        else:
            seeds = X.copy()
        # Shift each seed toward density peak
        converged = []
        for seed in seeds:
            point = seed.copy()
            for _ in range(self.max_iter):
                dists = np.sqrt(((X - point) ** 2).sum(axis=1))
                within = dists <= bw
                if not np.any(within):
                    break
                new_point = X[within].mean(axis=0)
                if np.linalg.norm(new_point - point) < 1e-6:
                    point = new_point
                    break
                point = new_point
            converged.append(point)
        converged = np.array(converged)
        # De-duplicate converged points
        centers = []
        used = np.zeros(len(converged), dtype=bool)
        for i in range(len(converged)):
            if used[i]:
                continue
            close = np.sqrt(((converged[i:] - converged[i]) ** 2).sum(axis=1)) < bw
            indices = np.where(close)[0] + i
            used[indices] = True
            centers.append(converged[indices].mean(axis=0))
        self.cluster_centers_ = np.array(centers)
        # Assign labels
        dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
        self.labels_ = np.argmin(dists, axis=1)
        if not self.cluster_all:
            min_dists = np.min(dists, axis=1)
            self.labels_[min_dists > bw] = -1
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
        return np.argmin(dists, axis=1)

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# OPTICS
# ---------------------------------------------------------------------------

class OPTICS(BaseEstimator):
    """Ordering Points To Identify the Clustering Structure."""

    def __init__(self, *, min_samples=5, max_eps=np.inf, metric='minkowski',
                 p=2, metric_params=None, cluster_method='xi', eps=None,
                 xi=0.05, predecessor_correction=True, min_cluster_size=None,
                 algorithm='auto', leaf_size=30, memory=None, n_jobs=None):
        self.min_samples = min_samples
        self.max_eps = max_eps
        self.metric = metric
        self.p = p
        self.metric_params = metric_params
        self.cluster_method = cluster_method
        self.eps = eps
        self.xi = xi
        self.predecessor_correction = predecessor_correction
        self.min_cluster_size = min_cluster_size
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.memory = memory
        self.n_jobs = n_jobs
        self.labels_ = None
        self.reachability_ = None
        self.ordering_ = None
        self.core_distances_ = None

    def _pairwise_distances(self, X):
        if self.metric == 'minkowski':
            diff = X[:, None] - X[None]
            return np.sum(np.abs(diff) ** self.p, axis=2) ** (1.0 / self.p)
        return np.sqrt(((X[:, None] - X[None]) ** 2).sum(axis=2))

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = len(X)
        dists = self._pairwise_distances(X)
        # Core distances: distance to min_samples-th nearest neighbor
        sorted_dists = np.sort(dists, axis=1)
        ms = min(self.min_samples, n - 1)
        self.core_distances_ = sorted_dists[:, ms]
        reachability = np.full(n, np.inf)
        processed = np.zeros(n, dtype=bool)
        ordering = []
        # Start from point with smallest core distance
        current = np.argmin(self.core_distances_)
        for _ in range(n):
            processed[current] = True
            ordering.append(current)
            # Update reachability for unprocessed neighbors
            for j in range(n):
                if processed[j]:
                    continue
                if dists[current, j] <= self.max_eps:
                    reach = max(self.core_distances_[current], dists[current, j])
                    if reach < reachability[j]:
                        reachability[j] = reach
            # Pick next unprocessed point with smallest reachability
            unprocessed = np.where(~processed)[0]
            if len(unprocessed) == 0:
                break
            current = unprocessed[np.argmin(reachability[unprocessed])]
        self.ordering_ = np.array(ordering)
        self.reachability_ = reachability
        # Extract clusters using DBSCAN-like method on reachability
        if self.cluster_method == 'dbscan':
            cut_eps = self.eps if self.eps is not None else self.max_eps
            labels = np.full(n, -1, dtype=int)
            cluster_id = -1
            for idx in self.ordering_:
                if reachability[idx] > cut_eps:
                    if self.core_distances_[idx] <= cut_eps:
                        cluster_id += 1
                        labels[idx] = cluster_id
                    else:
                        labels[idx] = -1
                else:
                    labels[idx] = cluster_id
        else:
            # xi method: simplified extraction
            labels = np.full(n, -1, dtype=int)
            reach_ordered = reachability[self.ordering_]
            cluster_id = 0
            min_cs = self.min_cluster_size if self.min_cluster_size else self.min_samples
            i = 0
            while i < n:
                if reach_ordered[i] < self.max_eps:
                    start = i
                    while i < n and reach_ordered[i] < self.max_eps:
                        i += 1
                    if i - start >= min_cs:
                        for j in range(start, i):
                            labels[self.ordering_[j]] = cluster_id
                        cluster_id += 1
                else:
                    i += 1
        self.labels_ = labels
        return self

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# Birch
# ---------------------------------------------------------------------------

class Birch(BaseEstimator):
    """BIRCH incremental clustering."""

    def __init__(self, *, threshold=0.5, branching_factor=50, n_clusters=3,
                 compute_labels=True, copy=True):
        self.threshold = threshold
        self.branching_factor = branching_factor
        self.n_clusters = n_clusters
        self.compute_labels = compute_labels
        self.copy = copy
        self.subcluster_centers_ = None
        self.subcluster_labels_ = None
        self.labels_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        # Build sub-clusters: simplified CF-tree using threshold merging
        centers = []
        counts = []
        for point in X:
            if len(centers) == 0:
                centers.append(point.copy())
                counts.append(1)
                continue
            c_arr = np.array(centers)
            dists = np.sqrt(((c_arr - point) ** 2).sum(axis=1))
            nearest = np.argmin(dists)
            if dists[nearest] < self.threshold:
                n_c = counts[nearest]
                centers[nearest] = (centers[nearest] * n_c + point) / (n_c + 1)
                counts[nearest] += 1
            elif len(centers) < self.branching_factor * self.n_clusters:
                centers.append(point.copy())
                counts.append(1)
            else:
                nearest = np.argmin(dists)
                n_c = counts[nearest]
                centers[nearest] = (centers[nearest] * n_c + point) / (n_c + 1)
                counts[nearest] += 1
        self.subcluster_centers_ = np.array(centers)
        # Final clustering of sub-cluster centers
        if self.n_clusters is not None and len(self.subcluster_centers_) > self.n_clusters:
            km = KMeans(n_clusters=self.n_clusters, n_init=3, random_state=0)
            km.fit(self.subcluster_centers_)
            self.subcluster_labels_ = km.labels_
        else:
            self.subcluster_labels_ = np.arange(len(self.subcluster_centers_))
        # Assign labels to original data
        if self.compute_labels:
            dists = np.sqrt(((X[:, None] - self.subcluster_centers_[None]) ** 2).sum(axis=2))
            nearest_sub = np.argmin(dists, axis=1)
            self.labels_ = self.subcluster_labels_[nearest_sub]
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, None] - self.subcluster_centers_[None]) ** 2).sum(axis=2))
        nearest_sub = np.argmin(dists, axis=1)
        return self.subcluster_labels_[nearest_sub]

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# AffinityPropagation
# ---------------------------------------------------------------------------

class AffinityPropagation(BaseEstimator):
    """Affinity Propagation clustering via message passing."""

    def __init__(self, *, damping=0.5, max_iter=200, convergence_iter=15,
                 copy=True, preference=None, affinity='euclidean',
                 verbose=False, random_state=None):
        self.damping = damping
        self.max_iter = max_iter
        self.convergence_iter = convergence_iter
        self.copy = copy
        self.preference = preference
        self.affinity = affinity
        self.verbose = verbose
        self.random_state = random_state
        self.cluster_centers_indices_ = None
        self.cluster_centers_ = None
        self.labels_ = None
        self.n_iter_ = 0

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = X.shape[0]
        # Similarity matrix (negative squared euclidean)
        if self.affinity == 'euclidean':
            S = -((X[:, None] - X[None]) ** 2).sum(axis=2)
        else:
            S = np.asarray(X, dtype=float)  # precomputed
        pref = self.preference if self.preference is not None else np.median(S)
        np.fill_diagonal(S, pref)
        R = np.zeros((n, n))  # responsibility
        A = np.zeros((n, n))  # availability
        lam = self.damping
        converge_count = 0
        old_labels = np.zeros(n, dtype=int)
        for iteration in range(self.max_iter):
            # Update responsibility
            AS = A + S
            max1 = np.max(AS, axis=1, keepdims=True)
            max_idx = np.argmax(AS, axis=1)
            AS2 = AS.copy()
            AS2[np.arange(n), max_idx] = -np.inf
            max2 = np.max(AS2, axis=1, keepdims=True)
            R_new = S - max1
            for i in range(n):
                R_new[i, max_idx[i]] = S[i, max_idx[i]] - max2[i, 0]
            R = lam * R + (1 - lam) * R_new
            # Update availability
            Rp = np.maximum(R, 0)
            np.fill_diagonal(Rp, np.diag(R))
            A_new = np.minimum(0, np.sum(Rp, axis=0, keepdims=True) - Rp)
            np.fill_diagonal(A_new, np.sum(np.maximum(R, 0), axis=0) - np.diag(R))
            A = lam * A + (1 - lam) * A_new
            # Check convergence
            exemplars = np.argmax(A + R, axis=1)
            labels = exemplars.copy()
            if np.array_equal(labels, old_labels):
                converge_count += 1
            else:
                converge_count = 0
            old_labels = labels.copy()
            if converge_count >= self.convergence_iter:
                break
        self.n_iter_ = iteration + 1
        # Identify exemplars
        E = np.diag(A + R) > 0
        if not np.any(E):
            self.labels_ = np.zeros(n, dtype=int)
            self.cluster_centers_indices_ = np.array([0])
            self.cluster_centers_ = X[:1].copy()
            return self
        self.cluster_centers_indices_ = np.where(E)[0]
        self.cluster_centers_ = X[self.cluster_centers_indices_].copy()
        # Assign labels
        dists = ((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2)
        self.labels_ = np.argmin(dists, axis=1)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = ((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2)
        return np.argmin(dists, axis=1)

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# BisectingKMeans
# ---------------------------------------------------------------------------

class BisectingKMeans(BaseEstimator):
    """Bisecting K-Means via recursive cluster splitting."""

    def __init__(self, n_clusters=8, *, init='random', n_init=1,
                 random_state=None, max_iter=300, verbose=0, tol=1e-4,
                 copy_x=True, algorithm='lloyd',
                 bisecting_strategy='biggest_inertia'):
        self.n_clusters = n_clusters
        self.init = init
        self.n_init = n_init
        self.random_state = random_state
        self.max_iter = max_iter
        self.verbose = verbose
        self.tol = tol
        self.copy_x = copy_x
        self.algorithm = algorithm
        self.bisecting_strategy = bisecting_strategy
        self.cluster_centers_ = None
        self.labels_ = None
        self.inertia_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = X.shape[0]
        # Start with all points in one cluster
        clusters = {0: np.arange(n)}
        centers = {0: X.mean(axis=0)}
        next_id = 1
        while len(clusters) < self.n_clusters:
            # Pick cluster to bisect
            if self.bisecting_strategy == 'biggest_inertia':
                best_key = max(clusters, key=lambda k: np.sum(
                    (X[clusters[k]] - centers[k]) ** 2) if len(clusters[k]) > 1 else -1)
            else:
                best_key = max(clusters, key=lambda k: len(clusters[k]))
            indices = clusters[best_key]
            if len(indices) < 2:
                break
            subset = X[indices]
            km = KMeans(n_clusters=2, n_init=max(self.n_init, 1),
                        max_iter=self.max_iter, tol=self.tol,
                        random_state=self.random_state)
            km.fit(subset)
            mask0 = km.labels_ == 0
            mask1 = km.labels_ == 1
            del clusters[best_key]
            del centers[best_key]
            clusters[next_id] = indices[mask0]
            centers[next_id] = km.cluster_centers_[0]
            next_id += 1
            clusters[next_id] = indices[mask1]
            centers[next_id] = km.cluster_centers_[1]
            next_id += 1
        # Assign final labels
        self.labels_ = np.zeros(n, dtype=int)
        center_list = []
        for label, (key, idx_arr) in enumerate(sorted(clusters.items())):
            self.labels_[idx_arr] = label
            center_list.append(centers[key])
        self.cluster_centers_ = np.array(center_list)
        self.inertia_ = sum(
            np.sum((X[self.labels_ == k] - self.cluster_centers_[k]) ** 2)
            for k in range(len(self.cluster_centers_)))
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        dists = np.sqrt(((X[:, None] - self.cluster_centers_[None]) ** 2).sum(axis=2))
        return np.argmin(dists, axis=1)

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# HDBSCAN
# ---------------------------------------------------------------------------

class HDBSCAN(BaseEstimator):
    """Simplified Hierarchical DBSCAN."""

    def __init__(self, min_cluster_size=5, *, min_samples=None,
                 cluster_selection_epsilon=0.0, max_cluster_size=None,
                 metric='euclidean', alpha=1.0, algorithm='auto',
                 leaf_size=40, n_jobs=None, cluster_selection_method='eom',
                 allow_single_cluster=False, store_centers=None):
        self.min_cluster_size = min_cluster_size
        self.min_samples = min_samples
        self.cluster_selection_epsilon = cluster_selection_epsilon
        self.max_cluster_size = max_cluster_size
        self.metric = metric
        self.alpha = alpha
        self.algorithm = algorithm
        self.leaf_size = leaf_size
        self.n_jobs = n_jobs
        self.cluster_selection_method = cluster_selection_method
        self.allow_single_cluster = allow_single_cluster
        self.store_centers = store_centers
        self.labels_ = None
        self.probabilities_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n = X.shape[0]
        ms = self.min_samples if self.min_samples is not None else self.min_cluster_size
        ms = min(ms, n - 1)
        # Pairwise distance
        dists = np.sqrt(((X[:, None] - X[None]) ** 2).sum(axis=2))
        # Core distances
        sorted_dists = np.sort(dists, axis=1)
        core_dist = sorted_dists[:, min(ms, n - 1)]
        # Mutual reachability distance
        mrd = np.maximum(dists, core_dist[:, None])
        mrd = np.maximum(mrd, core_dist[None, :])
        # Build MST using Prim's algorithm
        in_tree = np.zeros(n, dtype=bool)
        min_edge = np.full(n, np.inf)
        min_edge[0] = 0
        parent = np.full(n, -1, dtype=int)
        edge_weights = np.zeros(n)
        for _ in range(n):
            u = -1
            for v in range(n):
                if not in_tree[v] and (u == -1 or min_edge[v] < min_edge[u]):
                    u = v
            in_tree[u] = True
            edge_weights[u] = min_edge[u]
            for v in range(n):
                if not in_tree[v] and mrd[u, v] < min_edge[v]:
                    min_edge[v] = mrd[u, v]
                    parent[v] = u
        # Extract clusters using single-linkage hierarchy + epsilon
        # Sort edges by weight
        edges = [(edge_weights[i], parent[i], i) for i in range(1, n)]
        edges.sort()
        # Union-Find
        uf_parent = list(range(n))
        uf_size = [1] * n

        def find(x):
            while uf_parent[x] != x:
                uf_parent[x] = uf_parent[uf_parent[x]]
                x = uf_parent[x]
            return x

        def union(a, b):
            a, b = find(a), find(b)
            if a == b:
                return
            if uf_size[a] < uf_size[b]:
                a, b = b, a
            uf_parent[b] = a
            uf_size[a] += uf_size[b]

        # Process edges; stop merging when clusters are large enough
        mcs = self.min_cluster_size
        # We merge everything first, then extract by cutting
        for w, u, v in edges:
            if u >= 0:
                union(u, v)
        # Use DBSCAN-like extraction at a computed epsilon
        # Find a good epsilon from core distances
        if self.cluster_selection_epsilon > 0:
            cut_eps = self.cluster_selection_epsilon
        else:
            cut_eps = np.percentile(core_dist, 50) * self.alpha
        # Run DBSCAN at the cut epsilon
        labels = np.full(n, -1, dtype=int)
        neighborhoods = [np.where(dists[i] <= cut_eps)[0] for i in range(n)]
        core_mask = np.array([len(nb) >= ms for nb in neighborhoods])
        cluster_id = 0
        for i in range(n):
            if not core_mask[i] or labels[i] != -1:
                continue
            queue = [i]
            labels[i] = cluster_id
            head = 0
            while head < len(queue):
                pt = queue[head]
                head += 1
                if core_mask[pt]:
                    for nb in neighborhoods[pt]:
                        if labels[nb] == -1:
                            labels[nb] = cluster_id
                            queue.append(nb)
            cluster_id += 1
        # Filter out small clusters
        for cid in range(cluster_id):
            if np.sum(labels == cid) < mcs:
                labels[labels == cid] = -1
        # Re-number
        unique_labels = sorted(set(labels) - {-1})
        mapping = {old: new for new, old in enumerate(unique_labels)}
        mapping[-1] = -1
        self.labels_ = np.array([mapping[l] for l in labels])
        self.probabilities_ = np.where(self.labels_ >= 0, 1.0, 0.0)
        return self

    def fit_predict(self, X, y=None):
        self.fit(X)
        return self.labels_


# ---------------------------------------------------------------------------
# FeatureAgglomeration
# ---------------------------------------------------------------------------

class FeatureAgglomeration(BaseEstimator, TransformerMixin):
    """Agglomerative clustering on transposed features."""

    def __init__(self, n_clusters=2, *, metric='euclidean', memory=None,
                 connectivity=None, compute_full_tree='auto', linkage='ward',
                 pooling_func=np.mean, distance_threshold=None,
                 compute_distances=False):
        self.n_clusters = n_clusters
        self.metric = metric
        self.memory = memory
        self.connectivity = connectivity
        self.compute_full_tree = compute_full_tree
        self.linkage = linkage
        self.pooling_func = pooling_func
        self.distance_threshold = distance_threshold
        self.compute_distances = compute_distances
        self.labels_ = None
        self.n_features_in_ = None

    def fit(self, X, y=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.n_features_in_ = X.shape[1]
        # Cluster on transposed data (features as samples)
        linkage = 'single' if self.linkage == 'ward' else self.linkage
        agg = AgglomerativeClustering(
            n_clusters=self.n_clusters, linkage=linkage,
            metric=self.metric)
        agg.fit(X.T)
        self.labels_ = agg.labels_
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = X.shape[0]
        n_out = len(set(self.labels_))
        result = np.zeros((n_samples, n_out))
        for k in range(n_out):
            mask = self.labels_ == k
            result[:, k] = self.pooling_func(X[:, mask], axis=1)
        return result

    def inverse_transform(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n_samples = X.shape[0]
        result = np.zeros((n_samples, self.n_features_in_))
        for k in range(X.shape[1]):
            mask = self.labels_ == k
            result[:, mask] = X[:, k:k + 1]
        return result
